#include <bits/stdc++.h>
using namespace std;

double calculateProb(int moves, int i, int j, int row, int col, int n, 
                   vector<vector<vector<double>>>& dp, 
                   vector<pair<int,int>>& directions) {
   // Base case 
   if(moves == 0) {
       if(i == row && j == col) return 1;
       return 0;
   }

   // Check memoized value
   if(dp[moves][i][j] != -1) return dp[moves][i][j];

   dp[moves][i][j] = 0;

   // Try all possible moves
   for(const auto& direction : directions) {
       int prevI = i - direction.first;
       int prevJ = j - direction.second;

       // Boundary check
       if(prevI >= 0 && prevI < n && prevJ >= 0 && prevJ < n) {
           dp[moves][i][j] += calculateProb(moves-1, prevI, prevJ, row, col, n, dp, directions) / 8.0;
       }
   }

   return dp[moves][i][j];
}

int main() {
   int t;
   cin >> t;

   vector<pair<int,int>> directions = {
       {1, 2}, {1, -2}, {-1, 2}, {-1, -2},
       {2, 1}, {2, -1}, {-2, 1}, {-2, -1}
   };

   while(t--) {
       int n, k, row, col;
       cin >> n >> k >> row >> col;

       vector<vector<vector<double>>> dp(k+1, vector<vector<double>>(n, vector<double>(n, -1)));

       double totalProb = 0;
       for(int i = 0; i < n; i++) {
           for(int j = 0; j < n; j++) {
               totalProb += calculateProb(k, i, j, row, col, n, dp, directions);
           }
       }

       cout << fixed << setprecision(6) << totalProb << endl;
   }

   return 0;
}
